/* Layouts responsivos práticos */

.container {
  max-width: 1100px;
  margin: 0 auto;
  padding: 16px;
}

.header {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.nav {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.cards {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
}

.layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
  align-items: start;
}

@media (min-width: 768px) {
  .container { padding: 24px; }

  .header {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
  }

  .cards {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (min-width: 1024px) {
  .container { padding: 32px; }

  .cards {
    grid-template-columns: repeat(3, 1fr);
  }

  .layout {
    grid-template-columns: 280px 1fr;
  }
}
